import React, { useState } from "react";
import Buttons from "../Buttons";
import "./screenthree.css";
import ProgressBar from "../ProgressBar";
import { answerContent } from "./answerContent";

const ScreenThree = ({ screen, nmscreen, formData, handleInputChange }) => {
  const [otherConditions, setOtherConditions] = useState(formData.otherConditions || "");

  const handleDivClick = (name) => {
    const isSelected = formData.healthProblems.includes(name);
    const updatedHealthProblems = isSelected
      ? formData.healthProblems.filter((item) => item !== name)
      : [...formData.healthProblems, name];

    // If "Other Conditions" is being added or removed, handle the textarea value accordingly
    if (name === "Other Conditions") {
      if (!isSelected) {
        setOtherConditions(""); // Clear textarea if "Other Conditions" is selected
        handleInputChange("healthProblems", [...updatedHealthProblems, otherConditions].filter(Boolean));
      } else {
        setOtherConditions(""); // Clear textarea if "Other Conditions" is deselected
        handleInputChange("healthProblems", updatedHealthProblems.filter(item => item !== otherConditions));
      }
    } else {
      handleInputChange("healthProblems", updatedHealthProblems);
    }
  };

  const handleOtherConditionsChange = (e) => {
    const { value } = e.target;
    setOtherConditions(value);

    // Update healthProblems array
    const updatedHealthProblems = formData.healthProblems.includes("Other Conditions")
      ? [...formData.healthProblems.filter(item => item !== "Other Conditions"), value]
      : [...formData.healthProblems];
    
    handleInputChange("healthProblems", updatedHealthProblems);
    handleInputChange("otherConditions", value);
  };

  const progressPercentage = (nmscreen / 7) * 100; // Adjust based on your total screens

  return (
    <div id="screen3" className="screen3">
      <h1 className="title">Are you currently experiencing any health problems or have any chronic diseases?</h1>
      <div className="answer-container">
        <div
          className={`answer-card ${formData.healthProblems.includes("No, I am not experiencing any health problems.") ? "active" : ""}`}
          onClick={() => handleDivClick("No, I am not experiencing any health problems.")}
        >
          <h4>No, I am not experiencing any health problems.</h4>
        </div>
        {answerContent.map((answer) => (
          <div
            key={answer.id}
            className={`answer-card ${formData.healthProblems.includes(answer.name) ? "active" : ""}`}
            onClick={() => handleDivClick(answer.name)}
          >
            <h4>{answer.name}</h4>
            <p className="description">{answer.description}</p>
          </div>
        ))}
        <div
          className={`answer-card ${formData.healthProblems.includes("Other Conditions") ? "active" : ""}`}
          onClick={() => handleDivClick("Other Conditions")}
        >
          <h4>Other Conditions</h4>
          {formData.healthProblems.includes("Other Conditions") && (
            <textarea
              name="otherConditions"
              id="other-answer"
              placeholder="Please specify if comfortable"
              value={otherConditions}
              onChange={handleOtherConditionsChange}
            ></textarea>
          )}
        </div>
      </div>
      <Buttons changeScreen={screen} back={"screen2"} next={"screen4"} nb={2} nn={4} />
    </div>
  );
};

export default ScreenThree;
